from collections import defaultdict

class Solution(object):
    def countOfSubstrings(self, word, k):
        vowels = set('aeiou')
        def at_least(min_cons):
            n = len(word)
            ans = 0
            v_cnt = defaultdict(int)
            cons = 0
            left = 0
            for right in range(n):
                c = word[right]
                if c in vowels:
                    v_cnt[c] += 1
                else:
                    cons += 1
                while len(v_cnt) == 5 and cons >= min_cons:
                    ans += n - right
                    lc = word[left]
                    if lc in vowels:
                        v_cnt[lc] -= 1
                        if v_cnt[lc] == 0:
                            del v_cnt[lc]
                    else:
                        cons -= 1
                    left += 1
            return ans
        return at_least(k) - at_least(k + 1)
